export const SourceOnline: MessageFns<SourceOnline> = {
  encode(message: SourceOnline, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.version !== "") {
      writer.uint32(18).string(message.version);
    }
    if (message.timestamp !== undefined) {
      Timestamp.encode(toTimestamp(message.timestamp), writer.uint32(26).fork()).join();
    }
    if (message.platform !== "") {
      writer.uint32(34).string(message.platform);
    }
    if (message.os !== "") {
      writer.uint32(42).string(message.os);
    }
    if (message.arch !== "") {
      writer.uint32(50).string(message.arch);
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): SourceOnline {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseSourceOnline();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 2: {
          if (tag !== 18) {
            break;
          }

          message.version = reader.string();
          continue;
        }
        case 3: {
          if (tag !== 26) {
            break;
          }

          message.timestamp = fromTimestamp(Timestamp.decode(reader, reader.uint32()));
          continue;
        }
        case 4: {
          if (tag !== 34) {
            break;
          }

          message.platform = reader.string();
          continue;
        }
        case 5: {
          if (tag !== 42) {
            break;
          }

          message.os = reader.string();
          continue;
        }
        case 6: {
          if (tag !== 50) {
            break;
          }

          message.arch = reader.string();
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): SourceOnline {
    return {
      version: isSet(object.version) ? globalThis.String(object.version) : "",
      timestamp: isSet(object.timestamp) ? fromJsonTimestamp(object.timestamp) : undefined,
      platform: isSet(object.platform) ? globalThis.String(object.platform) : "",
      os: isSet(object.os) ? globalThis.String(object.os) : "",
      arch: isSet(object.arch) ? globalThis.String(object.arch) : "",
    };
  },

  toJSON(message: SourceOnline): unknown {
    const obj: any = {};
    if (message.version !== "") {
      obj.version = message.version;
    }
    if (message.timestamp !== undefined) {
      obj.timestamp = message.timestamp.toISOString();
    }
    if (message.platform !== "") {
      obj.platform = message.platform;
    }
    if (message.os !== "") {
      obj.os = message.os;
    }
    if (message.arch !== "") {
      obj.arch = message.arch;
    }
    return obj;
  },

  create<I extends Exact<DeepPartial<SourceOnline>, I>>(base?: I): SourceOnline {
    return SourceOnline.fromPartial(base ?? ({} as any));
  },
  fromPartial<I extends Exact<DeepPartial<SourceOnline>, I>>(object: I): SourceOnline {
    const message = createBaseSourceOnline();
    message.version = object.version ?? "";
    message.timestamp = object.timestamp ?? undefined;
    message.platform = object.platform ?? "";
    message.os = object.os ?? "";
    message.arch = object.arch ?? "";
    return message;
  },
};

